SELECT item, description
FROM parts
WHERE available_quantity < critical_quantity;

SELECT SUM(available_quantity) AS total_quantity, AVG(unit_price) AS average_price
FROM parts
WHERE vendor_id = 0;

SELECT vendors.vendor_name, parts.item
FROM parts
JOIN vendors ON parts.vendor_id = vendors.vendor_id;

SELECT part_number
FROM parts
WHERE part_id = 1;

SELECT SUM(available_quantity) AS total_available_quantity
FROM parts
WHERE available_quantity < critical_quantity;

SELECT vendor_name
FROM vendors
WHERE contact_email = 'andymark@example.com';

SELECT COUNT(user_id) AS active_users_count
FROM users
WHERE is_active = 1;

SELECT SUM(total_cost) AS total_order_cost
FROM orders
WHERE user_id = 0;

SELECT SUM(total_cost) AS total_order_cost
FROM orders
WHERE user_id = 5;

SELECT SUM(pq.quantity) AS total_quantity
FROM part_quantities pq
JOIN part_packs pp ON pq.part_id = pp.part_id;
